            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Precompute left decreasing segments (from right to left)
    const leftDec = new Array(n).fill(0);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            leftDec[i] = leftDec[i + 1] + 1;
        } else {
            leftDec[i] = 0;
        }
    }

    // Iterate through all possible p and q
    for (let p = 1; p < n - 2; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check if nums[l..p] is strictly increasing
            const l = p - leftInc[p];
            if (l >= p || l < 0) continue;

            // Check if nums[p..q] is strictly decreasing
            const decLen = q - p;
            if (leftDec[p] < decLen) continue;

            // Check if nums[q..r] is strictly increasing
            const r = q + rightInc[q];
            if (r <= q || r >= n) continue;

