    const n = nums.length;
    const incLen = new Array(n).fill(1);
    const dp_inc = new Array(n).fill(0);
    dp_inc[0] = nums[0];
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i-1]) {
            incLen[i] = incLen[i-1] + 1;
            dp_inc[i] = dp_inc[i-1] + nums[i];
        } else {
            incLen[i] = 1;
            dp_inc[i] = nums[i];
        }
    }

    const dp_mountain = new Array(n).fill(-Infinity);
    for (let i = 2; i < n; i++) {
        if (nums[i] < nums[i-1]) {
            if (dp_mountain[i-1] !== -Infinity) {
                dp_mountain[i] = dp_mountain[i-1] + nums[i];
            }
            if (incLen[i-1] >= 2) {
                const new_mountain = dp_inc[i-1] + nums[i];
                if (new_mountain > dp_mountain[i] || dp_mountain[i] === -Infinity) {
                    dp_mountain[i] = new_mountain;
                }
            }
        }
    }

    const lenRightInc = new Array(n).fill(1);
    const rightInc = new Array(n).fill(0);
    rightInc[n-1] = nums[n-1];
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i+1]) {
            lenRightInc[i] = lenRightInc[i+1] + 1;
            rightInc[i] = nums[i] + rightInc[i+1];
        } else {
            lenRightInc[i] = 1;
            rightInc[i] = nums[i];
        }
    }

    let ans = -Infinity;
    for (let i = 2; i < n - 1; i++) {
        if (dp_mountain[i] !== -Infinity && lenRightInc[i] >= 2) {
            const totalSum = dp_mountain[i] + rightInc[i] - nums[i];
            if (totalSum > ans) {
                ans = totalSum;
            }
        }
    }

    return ans;
}
