    // Precompute left increasing and right increasing segments
    const leftInc = new Array(n).fill(0);
    const rightInc = new Array(n).fill(0);

    // Fill leftInc: leftInc[i] is the largest index <= i where nums[l..i] is strictly increasing
    leftInc[0] = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1];
        } else {
            leftInc[i] = i;
        }
    }

    // Fill rightInc: rightInc[i] is the smallest index >= i where nums[i..r] is strictly increasing
    rightInc[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1];
        } else {
            rightInc[i] = i;
        }
    }

    // Iterate all possible p and q where p < q and nums[p] > nums[q]
    for (let p = 1; p < n - 2; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            if (nums[p] <= nums[q]) continue; // Not decreasing

            const l = leftInc[p];
            const r = rightInc[q];

            if (l >= p || r <= q) continue; // Invalid segments

            const sum = prefixSum[r + 1] - prefixSum[l];
            if (sum > maxSum) {
                maxSum = sum;
            }
        }
    }

    return maxSum;
